mapper.select:
SELECT YYYYMM, SITE as SITE_ORG, CASE WHEN SITE='HQ' Then '본사' WHEN SITE='VN' then 'VINA' else site end as SITE, 제품명, 제품번호, 품목자산분류, 품목대분류, 품목중분류, 품목소분류, 공정차수, 공정, 공정품명, 공정품번호, 자재명, 자재번호, 자재자산분류, 자재대분류, 자재중분류, 자재소분류, 투입단위, 소요량, 내부Loss율, 외부Loss율, 조립위치, 특이사항, 최초작성일, 최초작성자, 최종수정일, 최종수정자 FROM DOI_BOM_MAST where 1=1
and yyyymm = #{yyyymm}
and site = #{site}
ORDER BY 제품번호

mapper.insert:
INSERT INTO DOI_BOM_MAST
(
YYYYMM
, SITE
, 제품명
, 제품번호
, 품목자산분류
, 품목대분류
, 품목중분류
, 품목소분류
, 공정차수
, 공정
, 공정품명
, 공정품번호
, 자재명
, 자재번호
, 자재자산분류
, 자재대분류
, 자재중분류
, 자재소분류
, 투입단위
, 소요량
, 내부Loss율
, 외부Loss율
, 조립위치
, 특이사항
, 최초작성일
, 최초작성자
, 최종수정일
, 최종수정자
)
VALUES
(
#{yyyymm}
, CASE WHEN #{site}='본사' Then 'HQ'  WHEN #{site}='베트남' then 'VN' else left(#{site},2) end
, #{prodName}
, #{prodCode}
, #{prodInventoryClass}
, #{prodLargeClass}
, #{prodMidClass}
, #{prodSmallClass}
, #{processSeq}
, #{process}
, #{processMatName}
, #{processMatCode}
, #{matName}
, #{matCode}
, #{matInventoryClass}
, #{matLargeClass}
, #{matMidClass}
, #{matSmallClass}
, #{inputUnit}
, #{reqQty}
, #{inLossRate}
, #{outLossRate}
, #{assyLoc}
, #{etc}
, #{firstRegDate}
, #{firstRegId}
, #{lastModDate}
, #{lastModId}
);

mapper.delete:
DELETE FROM DOI_BOM_MAST
WHERE 1=1
and yyyymm = #{yyyymm}
and site = #{siteOrg}
and 제품번호 = #{prodCode}
and 자재번호 = #{matCode}

mapper.update:
UPDATE DOI_BOM_MAST
SET 제품명 = #{prodName}
,품목자산분류 = #{prodInventoryClass}
,품목대분류 = #{prodLargeClass}
,품목중분류 = #{prodMidClass}
,품목소분류 = #{prodSmallClass}
,공정차수 = #{processSeq}
,공정 = #{process}
,공정품명 = #{processMatName}
,공정품번호 = #{processMatCode}
,자재명 = #{matName}
,자재자산분류 = #{matInventoryClass}
,자재대분류 = #{matLargeClass}
,자재중분류 = #{matMidClass}
,자재소분류 = #{matSmallClass}
,투입단위 = #{inputUnit}
,소요량 = #{reqQty}
,내부Loss율 = #{inLossRate}
,외부Loss율 = #{outLossRate}
,조립위치 = #{assyLoc}
,특이사항 = #{etc}
,최초작성일 = #{firstRegDate}
,최초작성자 = #{firstRegId}
,최종수정일 = #{lastModDate}
,최종수정자 = #{lastModId}
WHERE 1=1
and yyyymm = #{yyyymm}
and site = #{siteOrg}
and 제품번호 = #{prodCode}
and 자재번호 = #{matCode}
;
